   118→
   119→### 2.4 Create `backend/src/services/SessionManager.ts`
   120→
   121→```typescript
   122→import { v4 as uuidv4 } from 'uuid';
   123→import * as pty from 'node-pty';
   124→import * as fs from 'fs/promises';
   125→import * as path from 'path';
   126→import { EventEmitter } from 'events';
   127→import type { Session } from '../types';
   128→
   129→export class SessionManager extends EventEmitter {
   130→  private sessions: Map<string, Session> = new Map();
   131→  private workspacesDir = path.join(process.cwd(), 'workspaces');
   132→
   133→  async createSession(options: { name?: string } = {}): Promise<Session> {
   134→    const id = uuidv4();
   135→    const name = options.name || `session-${id.slice(0, 8)}`;
   136→    const workDir = path.join(this.workspacesDir, id);
   137→
   138→    // Create workspace directory
   139→    await fs.mkdir(workDir, { recursive: true });
   140→
   141→    // Spawn Claude Code CLI
   142→    const cliProcess = this.spawnClaudeCode(id, workDir);
   143→
   144→    const session: Session = {
   145→      id,
   146→      name,
   147→      status: 'starting',
   148→      workingDirectory: workDir,
   149→      cliProcess,
   150→      createdAt: new Date(),
   151→      lastActivity: new Date(),
   152→      commandsExecuted: 0
   153→    };
   154→
   155→    this.sessions.set(id, session);
   156→
   157→    // Wait for CLI to be ready
   158→    cliProcess.onData((data: string) => {
   159→      if (data.includes('Enter a command') || data.includes('How can I help')) {
   160→        session.status = 'ready';
   161→        this.emit('session:ready', session);
   162→      }
   163→      // Emit all output for dashboard
   164→      this.emit('session:output', { sessionId: id, data });
   165→    });
   166→
   167→    this.emit('session:created', session);
   168→    return session;
   169→  }
   170→
   171→  private spawnClaudeCode(sessionId: string, workDir: string) {
   172→    const cli = pty.spawn('claude', ['-p', '--output-format', 'json'], {
   173→      name: 'xterm-color',
   174→      cols: 80,
   175→      rows: 24,
   176→      cwd: workDir,
   177→      env: {
   178→        ...process.env,
   179→        CLAUDE_SESSION_ID: sessionId,
   180→        CLAUDE_HOOKS_ENABLED: 'true'
   181→      }
   182→    });
   183→
   184→    cli.onExit(({ exitCode }) => {
   185→      const session = this.sessions.get(sessionId);
   186→      if (session) {
   187→        session.status = 'terminated';
   188→        this.emit('session:terminated', { sessionId, exitCode });
   189→      }
   190→    });
   191→
   192→    return cli;
   193→  }
   194→
   195→  sendCommand(sessionId: string, command: string): void {
   196→    const session = this.sessions.get(sessionId);
   197→    if (!session || session.status === 'terminated') {
   198→      throw new Error(`Session ${sessionId} not found or terminated`);
   199→    }
   200→
   201→    session.cliProcess?.write(command + '\n');
   202→    session.status = 'busy';
   203→    session.lastActivity = new Date();
   204→    session.commandsExecuted++;
   205→
   206→    this.emit('session:busy', session);
   207→  }
   208→
   209→  terminateSession(sessionId: string): void {
   210→    const session = this.sessions.get(sessionId);
   211→    if (!session) return;
   212→
   213→    session.cliProcess?.kill();
   214→    session.status = 'terminated';
   215→    this.emit('session:terminated', { sessionId });
   216→  }
   217→
   218→  getSession(sessionId: string): Session | undefined {
   219→    return this.sessions.get(sessionId);
   220→  }
   221→
   222→  getAllSessions(): Session[] {
   223→    return Array.from(this.sessions.values());
   224→  }
   225→
   226→  handleHookEvent(event: any): void {
   227→    const session = this.sessions.get(event.session_id);
   228→    if (!session) return;
   229→
   230→    this.emit('session:hook', { sessionId: event.session_id, event });
   231→
   232→    // Update status based on hook
   233→    if (event.hook_event_name === 'Stop' && session.status === 'busy') {
   234→      session.status = 'ready';
   235→      this.emit('session:ready', session);
   236→    }
   237→  }
   238→}
   239→```
