   241→### 2.5 Create `backend/src/websocket/DashboardSocket.ts`
   242→
   243→```typescript
   244→import { Server as WebSocketServer } from 'ws';
   245→import { SessionManager } from '../services/SessionManager';
   246→import type { Session } from '../types';
   247→
   248→export function setupDashboardSocket(wss: WebSocketServer, sessionManager: SessionManager) {
   249→  // Forward session events to all dashboard clients
   250→  sessionManager.on('session:created', (session: Session) => {
   251→    broadcast({ type: 'session:created', session });
   252→  });
   253→
   254→  sessionManager.on('session:ready', (session: Session) => {
   255→    broadcast({ type: 'session:updated', session });
   256→  });
   257→
   258→  sessionManager.on('session:busy', (session: Session) => {
   259→    broadcast({ type: 'session:updated', session });
   260→  });
   261→
   262→  sessionManager.on('session:terminated', ({ sessionId }) => {
   263→    broadcast({ type: 'session:terminated', sessionId });
   264→  });
   265→
   266→  sessionManager.on('session:output', ({ sessionId, data }) => {
   267→    broadcast({ type: 'session:output', sessionId, data });
   268→  });
   269→
   270→  sessionManager.on('session:hook', ({ sessionId, event }) => {
   271→    broadcast({ type: 'session:hook', sessionId, event });
   272→  });
   273→
   274→  wss.on('connection', (ws) => {
   275→    console.log('Dashboard client connected');
   276→
   277→    // Send current sessions on connect
   278→    ws.send(JSON.stringify({
   279→      type: 'init',
   280→      sessions: sessionManager.getAllSessions()
   281→    }));
   282→
   283→    ws.on('message', (data) => {
   284→      try {
   285→        const msg = JSON.parse(data.toString());
   286→        handleClientMessage(ws, msg, sessionManager);
   287→      } catch (err) {
   288→        console.error('Invalid message:', err);
   289→      }
   290→    });
   291→
   292→    ws.on('close', () => {
   293→      console.log('Dashboard client disconnected');
   294→    });
   295→  });
   296→
   297→  function broadcast(message: any) {
   298→    wss.clients.forEach((client) => {
   299→      if (client.readyState === 1) { // OPEN
   300→        client.send(JSON.stringify(message));
   301→      }
   302→    });
   303→  }
   304→
   305→  function handleClientMessage(ws: any, msg: any, sessionManager: SessionManager) {
   306→    switch (msg.type) {
   307→      case 'subscribe':
   308→        // Handle session-specific subscriptions
   309→        break;
   310→      case 'command':
   311→        sessionManager.sendCommand(msg.sessionId, msg.command);
   312→        break;
   313→      case 'terminate':
   314→        sessionManager.terminateSession(msg.sessionId);
   315→        break;
   316→    }
   317→  }
   318→}
   319→```
