   649→### 4.5 Create `agent/stt/deepgram.py`
   650→
   651→```python
   652→from deepgram import DeepgramClient, DeepgramClientOptions, LiveTranscriptionEvents, LiveOptions
   653→from ..config import Config
   654→import asyncio
   655→
   656→class DeepgramSTT:
   657→    def __init__(self):
   658→        config = DeepgramClientOptions({"api_key": Config.DEEPGRAM_API_KEY})
   659→        self.client = DeepgramClient("", config)
   660→        self.deepgram_live = self.client.listen.websocket.v("1")
   661→
   662→    def on_message(self, *args, **kwargs):
   663→        # Handle transcription results
   664→        pass
   665→
   666→    async def transcribe_stream(self, audio_stream):
   667→        """Stream audio and get transcriptions"""
   668→        options = LiveOptions(
