     1→import { v4 as uuidv4 } from 'uuid';
     2→import { spawn } from 'child_process';
     3→import * as fs from 'fs/promises';
     4→import * as path from 'path';
     5→import { EventEmitter } from 'events';
     6→import type { Session } from '../types/index.js';
     7→
     8→export class SessionManager extends EventEmitter {
     9→  private sessions: Map<string, Session> = new Map();
    10→  private workspacesDir = path.join(process.cwd(), 'workspaces');
    11→
    12→  async createSession(options: { name?: string } = {}): Promise<Session> {
    13→    const id = uuidv4();
    14→    const name = options.name || `session-${id.slice(0, 8)}`;
    15→    const workDir = path.join(this.workspacesDir, id);
    16→
    17→    // Create workspace directory
    18→    await fs.mkdir(workDir, { recursive: true });
    19→
    20→    // VIRTUAL SESSION - No persistent CLI process
    21→    // Each command runs independently with claude -p
    22→    const session: Session = {
    23→      id,
    24→      name,
    25→      status: 'ready',
    26→      workingDirectory: workDir,
    27→      createdAt: new Date(),
    28→      lastActivity: new Date(),
    29→      commandsExecuted: 0
    30→    };
    31→
    32→    this.sessions.set(id, session);
    33→    this.emit('session:created', session);
    34→    this.emit('session:ready', session);
    35→
    36→    return session;
    37→  }
    38→
    39→  async sendCommand(sessionId: string, command: string): Promise<void> {
    40→    const session = this.sessions.get(sessionId);
    41→    if (!session || session.status === 'terminated') {
    42→      throw new Error(`Session ${sessionId} not found or terminated`);
    43→    }
    44→
    45→    session.status = 'busy';
    46→    session.lastActivity = new Date();
    47→    session.commandsExecuted++;
    48→    this.emit('session:busy', session);
    49→
    50→    // SOLUTION: Execute claude -p command as ONE-SHOT process
    51→    // This WORKS on Windows because -p doesn't need TTY!
    52→    const isWindows = process.platform === 'win32';
    53→    const claude = isWindows ? 'npx.cmd' : 'npx';
    54→
    55→    return new Promise<void>((resolve, reject) => {
    56→      const cli = spawn(claude, ['-y', '@anthropic-ai/claude-code', '-p', command], {
    57→        cwd: session.workingDirectory,
    58→        env: {
    59→          ...process.env,
    60→          CLAUDE_SESSION_ID: sessionId
    61→        },
    62→        shell: true,
    63→        stdio: ['ignore', 'pipe', 'pipe']
    64→      });
    65→
    66→      let output = '';
    67→      let errorOutput = '';
    68→
    69→      if (cli.stdout) {
    70→        cli.stdout.on('data', (data: Buffer) => {
    71→          const chunk = data.toString();
    72→          output += chunk;
    73→          this.emit('session:output', { sessionId, data: chunk });
    74→        });
    75→      }
    76→
    77→      if (cli.stderr) {
    78→        cli.stderr.on('data', (data: Buffer) => {
    79→          const chunk = data.toString();
    80→          errorOutput += chunk;
    81→          this.emit('session:output', { sessionId, data: chunk });
    82→        });
    83→      }
    84→
    85→      cli.on('close', (code) => {
    86→        session.status = 'ready';
    87→        this.emit('session:ready', session);
    88→
    89→        if (code === 0 || output.length > 0) {
    90→          resolve();
    91→        } else {
    92→          reject(new Error(`Command failed with code ${code}: ${errorOutput}`));
    93→        }
    94→      });
    95→
    96→      cli.on('error', (err) => {
    97→        session.status = 'ready';
    98→        this.emit('session:ready', session);
    99→        reject(err);
   100→      });
   101→    });
   102→  }
   103→
   104→  terminateSession(sessionId: string): void {
   105→    const session = this.sessions.get(sessionId);
   106→    if (!session) return;
   107→
   108→    session.status = 'terminated';
   109→    this.emit('session:terminated', { sessionId });
   110→  }
   111→
   112→  getSession(sessionId: string): Session | undefined {
   113→    return this.sessions.get(sessionId);
   114→  }
   115→
   116→  getAllSessions(): Session[] {
   117→    return Array.from(this.sessions.values());
   118→  }
   119→
   120→  handleHookEvent(event: any): void {
   121→    const session = this.sessions.get(event.session_id);
   122→    if (!session) return;
   123→
   124→    this.emit('session:hook', { sessionId: event.session_id, event });
   125→
   126→    // Update status based on hook
   127→    if (event.hook_event_name === 'Stop' && session.status === 'busy') {
   128→      session.status = 'ready';
   129→      this.emit('session:ready', session);
   130→    }
   131→  }
   132→}
   133→

