     1→import { useState, useEffect } from 'react';
     2→import './App.css';
     3→
     4→interface Session {
     5→  id: string;
     6→  name: string;
     7→  status: string;
     8→  createdAt: string;
     9→  commandsExecuted: number;
    10→}
    11→
    12→function App() {
    13→  const [sessions, setSessions] = useState<Session[]>([]);
    14→  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
    15→  const [output, setOutput] = useState<string[]>([]);
    16→  const [wsConnected, setWsConnected] = useState(false);
    17→
    18→  useEffect(() => {
    19→    const ws = new WebSocket('ws://localhost:3000/ws');
    20→
    21→    ws.onopen = () => {
    22→      console.log('Connected to dashboard');
    23→      setWsConnected(true);
    24→    };
    25→
    26→    ws.onclose = () => {
    27→      console.log('Disconnected from dashboard');
    28→      setWsConnected(false);
    29→    };
    30→
    31→    ws.onmessage = (event) => {
    32→      const data = JSON.parse(event.data);
    33→
    34→      switch (data.type) {
    35→        case 'init':
    36→          setSessions(data.sessions);
    37→          break;
    38→        case 'session:created':
    39→          setSessions(prev => [...prev, data.session]);
    40→          break;
    41→        case 'session:updated':
    42→          setSessions(prev => prev.map(s => s.id === data.session.id ? data.session : s));
    43→          break;
    44→        case 'session:output':
    45→          if (selectedSession && data.sessionId === selectedSession.id) {
    46→            setOutput(prev => [...prev, data.data]);
    47→          }
    48→          break;
    49→        case 'session:terminated':
    50→          setSessions(prev => prev.filter(s => s.id !== data.sessionId));
    51→          if (selectedSession?.id === data.sessionId) {
    52→            setSelectedSession(null);
    53→            setOutput([]);
    54→          }
    55→          break;
    56→      }
    57→    };
    58→
    59→    ws.onerror = (error) => {
    60→      console.error('WebSocket error:', error);
    61→    };
    62→
    63→    return () => {
    64→      ws.close();
    65→    };
    66→  }, [selectedSession]);
    67→
    68→  const createSession = async () => {
    69→    await fetch('http://localhost:3000/api/session', {
    70→      method: 'POST',
    71→      headers: { 'Content-Type': 'application/json' },
    72→      body: JSON.stringify({})
    73→    });
    74→  };
    75→
    76→  const terminateSession = async (id: string) => {
    77→    await fetch(`http://localhost:3000/api/session/${id}`, {
    78→      method: 'DELETE'
    79→    });
    80→  };
    81→
    82→  const sendCommand = async (command: string) => {
    83→    if (!selectedSession) return;
    84→    await fetch(`http://localhost:3000/api/session/${selectedSession.id}/command`, {
    85→      method: 'POST',
    86→      headers: { 'Content-Type': 'application/json' },
    87→      body: JSON.stringify({ command })
    88→    });
    89→  };
    90→
    91→  return (
    92→    <div className="app">
    93→      <header>
    94→        <h1>Voice-Controlled Claude Code</h1>
    95→        <div className="header-actions">
    96→          <span className={`connection-status ${wsConnected ? 'connected' : 'disconnected'}`}>
    97→            {wsConnected ? '● Connected' : '○ Disconnected'}
    98→          </span>
    99→          <button onClick={createSession}>+ New Session</button>
   100→        </div>
   101→      </header>
   102→
   103→      <main>
   104→        <div className="sessions-panel">
   105→          <h2>Sessions</h2>
   106→          {sessions.length === 0 ? (
   107→            <div className="empty-sessions">No active sessions</div>
   108→          ) : (
   109→            sessions.map(session => (
   110→              <div
   111→                key={session.id}
   112→                className={`session-card ${selectedSession?.id === session.id ? 'active' : ''}`}
   113→                onClick={() => {
   114→                  setSelectedSession(session);
   115→                  setOutput([]);
   116→                }}
   117→              >
   118→                <h3>{session.name}</h3>
   119→                <span className={`status status-${session.status}`}>{session.status}</span>
   120→                <span className="commands">{session.commandsExecuted} commands</span>
   121→                <button
   122→                  className="terminate-btn"
   123→                  onClick={(e) => { e.stopPropagation(); terminateSession(session.id); }}
   124→                >
   125→                  Stop
   126→                </button>
   127→              </div>
   128→            ))
   129→          )}
   130→        </div>
   131→
   132→        <div className="session-panel">
   133→          {selectedSession ? (
   134→            <>
   135→              <div className="session-header">
   136→                <h2>{selectedSession.name}</h2>
   137→                <span className={`status status-${selectedSession.status}`}>
   138→                  {selectedSession.status}
   139→                </span>
   140→              </div>
   141→
   142→              <div className="command-bar">
   143→                <input
   144→                  type="text"
   145→                  placeholder="Enter command..."
   146→                  onKeyPress={(e) => {
   147→                    if (e.key === 'Enter') {
   148→                      sendCommand((e.target as HTMLInputElement).value);
   149→                      (e.target as HTMLInputElement).value = '';
   150→                    }
   151→                  }}
   152→                />
   153→                <button className="voice-btn">Voice</button>
   154→              </div>
   155→
   156→              <div className="output">
   157→                {output.length === 0 ? (
   158→                  <div className="empty-output">Waiting for output...</div>
   159→                ) : (
   160→                  output.map((line, i) => (
   161→                    <div key={i} className="output-line">{line}</div>
   162→                  ))
   163→                )}
   164→              </div>
   165→            </>
   166→          ) : (
   167→            <div className="empty-state">Select a session to view</div>
   168→          )}
   169→        </div>
   170→      </main>
   171→    </div>
   172→  );
   173→}
   174→
   175→export default App;
   176→

